import{_ as e,o as n,c as r,ag as s}from"./chunks/framework.gU7RhlGX.js";const a="/Awesome-AI-Pedia/assets/02-infographic-evolution-path.C6xI3lXx.png",u=JSON.parse('{"title":"Harness Engineering 介绍","description":"","frontmatter":{},"headers":[],"relativePath":"Harness Engineering/Harness Engineering介绍.md","filePath":"Harness Engineering/Harness Engineering介绍.md","lastUpdated":1776422487000}'),i={name:"Harness Engineering/Harness Engineering介绍.md"};function o(l,t,g,d,h,c){return n(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="harness-engineering-介绍" tabindex="-1">Harness Engineering 介绍 <a class="header-anchor" href="#harness-engineering-介绍" aria-label="Permalink to &quot;Harness Engineering 介绍&quot;">​</a></h1><p>Harness Engineering 是 2025-2026 年兴起的 AI 工程新范式。其核心在于为 AI Agent 构建<strong>约束（Constraints）</strong>、<strong>反馈（Feedback）<strong>与</strong>控制系统（Control Systems）</strong>，旨在让 AI 在人类设定的边界内可靠、高效地工作。</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>核心理念：从“编写代码”转向“设计让 Agent 可靠运行的环境”。</p></div><hr><h2 id="_1-定义与起源" tabindex="-1">1. 定义与起源 <a class="header-anchor" href="#_1-定义与起源" aria-label="Permalink to &quot;1. 定义与起源&quot;">​</a></h2><p>Harness Engineering（马具/驾驭工程）由 HashiCorp 联合创始人 <strong>Mitchell Hashimoto</strong> 在 2026 年初提出。它标志着软件工程核心竞争力的重大转移：超越了早期的提示词工程 (Prompt Engineering) 和上下文工程 (Context Engineering)。</p><p><strong>“Harness” 的精准隐喻：</strong> 驾驭不等同于控制。真正的驾驭工程师不会尝试“硬编码” AI 的每一步行为，而是建立一套框架、约束和引导机制，让 AI 在其中自由发挥能力，同时保持可预测性和可靠性。</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Mitchell Hashimoto 的核心观点：“每当你发现 Agent 犯了一个错误，就花时间设计一个解决方案，使 Agent 永远不再犯同样的错误。”</p></div><h2 id="_2-演进逻辑-从-prompt-到-harness" tabindex="-1">2. 演进逻辑：从 Prompt 到 Harness <a class="header-anchor" href="#_2-演进逻辑-从-prompt-到-harness" aria-label="Permalink to &quot;2. 演进逻辑：从 Prompt 到 Harness&quot;">​</a></h2><p>随着 AI 处理任务复杂度的增加，工程重点经历了三个阶段的演进：</p><table tabindex="0"><thead><tr><th style="text-align:left;">阶段</th><th style="text-align:left;">核心关注点</th><th style="text-align:left;">隐喻</th><th style="text-align:left;">解决的问题</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Prompt Engineering</strong> (2023)</td><td style="text-align:left;"><strong>说什么</strong></td><td style="text-align:left;">指令</td><td style="text-align:left;">如何通过提示词让 AI 交付单次结果。</td></tr><tr><td style="text-align:left;"><strong>Context Engineering</strong> (2025)</td><td style="text-align:left;"><strong>知道什么</strong></td><td style="text-align:left;">信息</td><td style="text-align:left;">如何通过 RAG 和动态上下文构建让 AI 获得所需信息。</td></tr><tr><td style="text-align:left;"><strong>Harness Engineering</strong> (2026)</td><td style="text-align:left;"><strong>在什么环境做事</strong></td><td style="text-align:left;">环境/闭环</td><td style="text-align:left;">如何构建约束、反馈与控制系统，让 Agent Reliable 执行任务。</td></tr></tbody></table><p><img src="'+a+'" alt="Evolution Path"></p><hr><h2 id="_3-harness-engineering-的三大支柱" tabindex="-1">3. Harness Engineering 的三大支柱 <a class="header-anchor" href="#_3-harness-engineering-的三大支柱" aria-label="Permalink to &quot;3. Harness Engineering 的三大支柱&quot;">​</a></h2><p>根据业界共识（如 Thoughtworks 专家 Birgitta Böckeler 的总结），Harness 由以下三个核心维度构成：</p><h3 id="维度一-上下文工程-context-2-0" tabindex="-1">维度一：上下文工程 (Context 2.0) <a class="header-anchor" href="#维度一-上下文工程-context-2-0" aria-label="Permalink to &quot;维度一：上下文工程 (Context 2.0)&quot;">​</a></h3><p>不再只是简单地填充窗口，而是<strong>确保 Agent 在正确的时机获得正确粒度的信息</strong>。</p><ul><li><strong>渐进式披露 (Progressive Disclosure)</strong>：将隐性知识转化为结构化信息。通过层级目录（如 <code>docs/ARCHITECTURE.md</code>）按需引导，而非盲目堆砌。</li><li><strong>运行时数据接入</strong>：提供日志、指标和环境映射，允许 Agent 使用 LogQL/PromQL 等工具进行动态查询。</li><li><strong>直接感知环境</strong>：通过 CDP 等协议让 Agent 操作浏览器，实现原生的 Bug 重现或 UI 验证。</li></ul><h3 id="维度二-架构约束-architectural-constraints" tabindex="-1">维度二：架构约束 (Architectural Constraints) <a class="header-anchor" href="#维度二-架构约束-architectural-constraints" aria-label="Permalink to &quot;维度二：架构约束 (Architectural Constraints)&quot;">​</a></h3><p>将“代码品味”（命名、依赖原则、边界等）编码为可强制执行的规则，实现“只在边界内行事”。</p><ul><li><strong>AI 友好型 Linter</strong>：传统的错误消息是给人看的，Harness 时代的 Linter 消息直接包含修复建议，便于 Agent 实现自主闭环。</li><li><strong>双轨审计机制</strong>：引入专门的“审计 Agent”对主开发 Agent 的代码提交进行实时审查和拦截。</li></ul><h3 id="维度三-熵管理与反馈回路-entropy-management" tabindex="-1">维度三：熵管理与反馈回路 (Entropy Management) <a class="header-anchor" href="#维度三-熵管理与反馈回路-entropy-management" aria-label="Permalink to &quot;维度三：熵管理与反馈回路 (Entropy Management)&quot;">​</a></h3><p>防止系统随时间推移而腐化，保障长期的可维护性。</p><ul><li><strong>反熵 Agent (Anti-Entropy)</strong>：定期扫描代码库，自动清理过时文档、漂移模式和无效依赖。</li><li><strong>实时演进</strong>：通过持续的监控与自动化验证修复系统缺陷，驱动 Agent 持续进化。</li></ul><h2 id="_4-核心实践-openai-的-codex-极端实验" tabindex="-1">4. 核心实践：OpenAI 的 Codex 极端实验 <a class="header-anchor" href="#_4-核心实践-openai-的-codex-极端实验" aria-label="Permalink to &quot;4. 核心实践：OpenAI 的 Codex 极端实验&quot;">​</a></h2><p>OpenAI 曾记录过一个极具代表性的实践案例：<strong>5 名工程师在 5 个月内交付了 100 万行代码，且其中包含 0 行人类手写代码。</strong></p><p><strong>关键成功因素：</strong></p><ol><li><strong>倒逼机制 (Forcing Function)</strong>：全团队禁止直接编写代码，迫使所有人集中精力构建 Harness（基础设施）。</li><li><strong>角色彻底转型</strong>：工程师从 Code Writer 进化为 <strong>Environment Designer</strong>。其日常工作由写逻辑转变为维护 <code>AGENTS.md</code>、编写自定义 Linter 以及建立可观测性栈。</li><li><strong>极高吞吐量</strong>：平均每人每日交付 3.5 个 PR，且大部分 Code Review 是由 Agent 对 Agent 完成的。</li></ol><hr><h2 id="_5-开发者如何构建自己的-harness" tabindex="-1">5. 开发者如何构建自己的 Harness？ <a class="header-anchor" href="#_5-开发者如何构建自己的-harness" aria-label="Permalink to &quot;5. 开发者如何构建自己的 Harness？&quot;">​</a></h2><ol><li><strong>精炼 <code>AGENTS.md</code> 索引</strong>： <ul><li>目录化：根目录文件应少于 100 行，仅作为导航。</li><li>模块化：将架构、设计和安全约束拆分到 <code>docs/*.md</code>。</li><li>层级化：支持子目录级的覆盖规则（如 <code>AGENTS.override.md</code>）。</li></ul></li><li><strong>闭环反馈回路</strong>： <ul><li>接入自动触发的测试、Lint 和验证工具。</li><li>优化反馈信息的格式，使其更易被 AI 解析和执行。</li></ul></li><li><strong>优化工作流习惯</strong>： <ul><li><strong>热启动</strong>：下班前启动 Agent 进行深度调研或并行探索。</li><li><strong>职能分离</strong>：将模糊需求明确拆分为“规划 (Planning)”和“执行 (Execution)”两个阶段。</li></ul></li><li><strong>建立评估体系 (Evals)</strong>： <ul><li>超越简单的 CI，建立一套针对 Agent 意向和产出质量的系统化评估工具。</li></ul></li></ol><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p><strong>Harness Engineering = 用工程手段“驯服”大模型，将 AI 转化为可靠的产品。</strong></p><p>软件工程团队的核心竞争力，正在从“谁的代码写得好”转向“谁能设计出更好的 Agent 运行环境”。</p>',35)])])}const m=e(i,[["render",o]]);export{u as __pageData,m as default};
